return items.map((item) => {
  const root = item.json || {};
  const body = root.body || {};
  const data = root.data || {};

  const fileBase64 =
    root.file_content_base64 ||
    body.file_content_base64 ||
    data.file_content_base64 ||
    root.file_data ||
    body.file_data ||
    data.file_data;

  const specId =
    root.spec_id ||
    body.spec_id ||
    data.spec_id ||
    root.specId ||
    body.specId ||
    data.specId;

  const normalizeId = (v) => {
    if (v === undefined || v === null) return '';
    if (typeof v === 'number') return String(v);
    const s = String(v).trim();
    if (!s) return '';
    const m = s.match(/\d+/);
    return m ? m[0] : s;
  };

  const fileName =
    root.file_name ||
    body.file_name ||
    data.file_name ||
    'Spec.pdf';

  if (!fileBase64) {
    throw new Error(`Webhook payload missing file_content_base64. Keys: ${Object.keys(root).join(', ')}`);
  }

  // Simple deterministic hash (no crypto required)
  const hashDjb2 = (str) => {
    let h = 5381;
    for (let i = 0; i < str.length; i++) {
      h = ((h << 5) + h) + str.charCodeAt(i);
      h |= 0;
    }
    return (h >>> 0).toString(16);
  };

  const pdfFingerprint = hashDjb2(fileBase64);

  return {
    json: {
      ...root,
      ...(Object.keys(body).length ? body : {}),
      ...(Object.keys(data).length ? data : {}),
      file_name: fileName,
      file_content_base64: fileBase64,
      pdf_fingerprint: pdfFingerprint,
      spec_id: normalizeId(specId),
    },
    binary: {
      data0: {
        data: fileBase64,
        mimeType: 'application/pdf',
        fileName,
      },
    },
  };
});

const promises = items.map(async (item, idx) => {
  const j = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || $items('Webhook Spec Upload')[idx]?.json || {};

  let pdf =
    j.file_content_base64 ||
    original.file_content_base64 ||
    j.file_data ||
    original.file_data ||
    '';

  if (pdf.startsWith('data:application/pdf;base64,')) {
    pdf = pdf.replace('data:application/pdf;base64,', '');
  }

  if (!pdf) {
    try {
      const buf = await this.helpers.getBinaryDataBuffer(idx, 'data0');
      pdf = buf.toString('base64');
    } catch (e) {}
  }

  const prompt = String(j.selected_prompt || j.extraction_system_message || '').trim();

  if (!pdf || !prompt) {
    throw new Error('Missing pdf or selected spec prompt');
  }

  return {
    json: {
      ...original,
      ...j,
      file_content_base64: pdf,
      claude_extract_body: {
        model: 'claude-sonnet-4-20250514',
        max_tokens: 8192,
        temperature: 0,
        messages: [
          {
            role: 'user',
            content: [
              {
                type: 'document',
                source: {
                  type: 'base64',
                  media_type: 'application/pdf',
                  data: pdf
                }
              },
              {
                type: 'text',
                text: prompt
              }
            ]
          }
        ]
      }
    },
    binary: item.binary
  };
});

return Promise.all(promises);

return items.map((item, idx) => {
  const j = item.json || {};
  const text = (j.content && j.content[0] && j.content[0].text) || '';
  let obj = {};
  try {
    obj = JSON.parse(text.trim());
  } catch (e) {
    const a = text.indexOf('{');
    const b = text.lastIndexOf('}');
    if (a >= 0 && b > a) {
      try { obj = JSON.parse(text.slice(a, b + 1)); } catch (_) {}
    }
  }
  return {
    json: {
      ...j,
      output: obj,
    },
    binary: item.binary
  };
});

return items.map((item, idx) => {
  const j = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || $items('Webhook Spec Upload')[idx]?.json || {};
  const out = j.output || j.data?.output || j.data || j.result?.output || j.result || j;
  return {
    json: {
      spec_id: j.spec_id || original.spec_id || original.specId || '',
      output: out,
    }
  };
});

return items.map((item, idx) => {
  const j = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || $items('Webhook Spec Upload')[idx]?.json || {};
  const out = j.output || j.data?.output || j.data || j.result?.output || j.result || j;

  const cleanText = (v) =>
    String(v ?? '')
      .trim()
      .replace(/\s+/g, ' ');

  const normalizeList = (v) => {
    if (!v) return [];
    if (Array.isArray(v)) return v.map(cleanText).filter(Boolean);
    if (typeof v === 'string') {
      return v.split(',').map(cleanText).filter(Boolean);
    }
    return [cleanText(v)].filter(Boolean);
  };

  const dedupeStrings = (arr) => {
    const seen = new Set();
    const result = [];
    for (const value of normalizeList(arr)) {
      const key = value.toLowerCase();
      if (!seen.has(key)) {
        seen.add(key);
        result.push(value);
      }
    }
    return result;
  };

  const dedupeObjects = (arr, keyFn) => {
    if (!Array.isArray(arr)) return [];
    const map = new Map();
    for (const obj of arr) {
      if (!obj || typeof obj !== 'object') continue;
      const key = keyFn(obj);
      if (!map.has(key)) map.set(key, obj);
    }
    return Array.from(map.values());
  };

  const normalizeEquivalents = (v) => dedupeStrings(v).join(', ');

  const normalizeNumber = (v) => {
    if (v === null || v === undefined || v === '') return v;
    if (typeof v === 'number') return v;
    let s = String(v).trim();
    if (!s) return v;
    s = s.replace(/,/g, '');
    if (/^-?\d+(\.\d+)?$/.test(s)) {
      const n = Number(s);
      return Number.isFinite(n) ? n : v;
    }
    return v;
  };

  const normalizeImpactUnit = (u) => {
    const s = String(u || '').trim().toLowerCase();
    if (['ft-lb','ft-lbs','ftlb','ftlbs','ft lb','ft lbs'].includes(s)) return 'ft-lbf';
    if (['j','joule','joules'].includes(s)) return 'ft-lbf';
    return s || 'ft-lbf';
  };

  const normalizeStrengthToPsi = (v, unit, property) => {
    const n = normalizeNumber(v);
    if (n === null || n === undefined || n === '') return n;

    const p = String(property || '').trim().toLowerCase();
    const u = String(unit || '').trim().toLowerCase();

    const isStrength =
      p.includes('yield') ||
      p.includes('tensile') ||
      p === 'ys' ||
      p === 'ts';

    if (!isStrength || typeof n !== 'number') return n;

    if (u === 'psi') return n;
    if (u === 'ksi' || u === 'kpsi') return n * 1000;
    if (u === 'mpa') return Math.round(n * 145.038);

    // Safety: a strength value below 1000 is usually ksi even if unit was missed.
    if (!u && n > 0 && n < 1000) return n * 1000;

    return n;
  };

  const normalizeMechUnit = (unit, property) => {
    const p = String(property || '').trim().toLowerCase();
    const u = String(unit || '').trim().toLowerCase();

    const isStrength =
      p.includes('yield') ||
      p.includes('tensile') ||
      p === 'ys' ||
      p === 'ts';

    if (isStrength) return 'psi';
    if (u === 'brinell' || u === 'hb' || u === 'hbw') return 'HBW';
    if (u === 'rockwell c') return 'hrc';
    return u;
  };

  const slug = (v) =>
    String(v ?? '')
      .trim()
      .toLowerCase()
      .replace(/&/g, 'and')
      .replace(/[^a-z0-9]+/g, '_')
      .replace(/^_+|_+$/g, '');

  const makeKey = (...parts) => parts.map(slug).join('|');

  const specCode = out.spec_code || out.specName || out.spec_name || j.spec_name || '';
  const specTitle = out.spec_title || out.product_name || out.productName || '';
  const displayName = out.display_name || (specCode && specTitle ? `${specCode} - ${specTitle}` : (out.spec_name || specCode));
  const customer = out.customer || j.spec_customer_name || '';
  const specKey = makeKey(customer, specCode);

  const productForms = dedupeObjects(Array.isArray(out.product_forms) ? out.product_forms : [], l =>
    [
      cleanText(l.form).toLowerCase(),
      l.thickness_min ?? '',
      l.thickness_max ?? '',
      cleanText(l.thickness_unit).toLowerCase()
    ].join('|')
  ).map(l => ({
    ...l,
    thickness_min: normalizeNumber(l.thickness_min),
    thickness_max: normalizeNumber(l.thickness_max),
    form_key: makeKey(specKey, l.form, l.thickness_min, l.thickness_max, l.thickness_unit)
  }));

  const chemLimits = dedupeObjects(Array.isArray(out.chem_limits) ? out.chem_limits : [], l =>
    [
      cleanText(l.rule_set_key || 'general').toLowerCase(),
      cleanText(l.element).toLowerCase(),
      JSON.stringify(l.applies_to_forms || []),
      JSON.stringify(l.applies_to_grades || []),
      l.min ?? '',
      l.max ?? '',
      cleanText(l.unit || '%').toLowerCase()
    ].join('|')
  ).map(l => ({
    ...l,
    element: cleanText(l.element).toLowerCase() === 'cb' ? 'nb' : cleanText(l.element).toLowerCase(),
    min: normalizeNumber(l.min),
    max: normalizeNumber(l.max),
    unit: l.unit || '%',
    row_key: makeKey(specKey, l.rule_set_key || 'general', 'chem', l.element, (l.applies_to_grades || []).join('_'), (l.applies_to_forms || []).join('_'))
  }));

  const mechLimits = dedupeObjects(Array.isArray(out.mech_limits) ? out.mech_limits : [], l =>
    [
      cleanText(l.rule_set_key || 'general').toLowerCase(),
      cleanText(l.property).toLowerCase(),
      cleanText(l.specimen_size).toLowerCase(),
      cleanText(l.direction).toLowerCase(),
      JSON.stringify(l.applies_to_forms || []),
      JSON.stringify(l.applies_to_grades || []),
      l.min ?? '',
      l.max ?? '',
      cleanText(l.unit).toLowerCase()
    ].join('|')
  ).map(l => ({
    ...l,
    min: normalizeStrengthToPsi(l.min, l.unit, l.property),
    max: normalizeStrengthToPsi(l.max, l.unit, l.property),
    unit: normalizeMechUnit(l.unit, l.property),
    row_key: makeKey(specKey, l.rule_set_key || 'general', 'mech', l.property, l.specimen_size, l.direction, (l.applies_to_grades || []).join('_'), (l.applies_to_forms || []).join('_'))
  }));

  const impactLimits = dedupeObjects(Array.isArray(out.impact_limits) ? out.impact_limits : [], l =>
    [
      cleanText(l.rule_set_key || 'general').toLowerCase(),
      l.temperature ?? '',
      cleanText(l.temperature_unit).toLowerCase(),
      cleanText(l.coupon_size).toLowerCase(),
      l.min_average ?? '',
      l.min_individual ?? '',
      cleanText(l.unit).toLowerCase(),
      cleanText(l.orientation).toLowerCase(),
      JSON.stringify(l.applies_to_forms || []),
      JSON.stringify(l.applies_to_grades || [])
    ].join('|')
  ).map(l => ({
    ...l,
    unit: normalizeImpactUnit(l.unit),
    temperature: normalizeNumber(l.temperature),
    min_average: normalizeNumber(l.min_average),
    min_individual: normalizeNumber(l.min_individual),
    row_key: makeKey(specKey, l.rule_set_key || 'general', 'impact', l.temperature, l.temperature_unit, l.coupon_size, l.orientation, (l.applies_to_grades || []).join('_'), (l.applies_to_forms || []).join('_'))
  }));

  const conditionRules = dedupeObjects(Array.isArray(out.condition_rules) ? out.condition_rules : [], l =>
    [
      cleanText(l.target_element).toLowerCase(),
      cleanText(l.condition_element).toLowerCase(),
      cleanText(l.condition_type).toLowerCase(),
      l.condition_threshold ?? '',
      l.target_adjustment ?? '',
      l.target_new_max ?? ''
    ].join('|')
  ).map(l => ({
    ...l,
    condition_threshold: normalizeNumber(l.condition_threshold),
    target_adjustment: normalizeNumber(l.target_adjustment),
    target_new_max: normalizeNumber(l.target_new_max),
    row_key: makeKey(specKey, 'condition', l.target_element, l.condition_element, l.condition_type, l.condition_threshold)
  }));

  const ceThresholds = dedupeObjects(Array.isArray(out.ce_thresholds) ? out.ce_thresholds : [], l =>
    [
      cleanText(l.rule_set_key || 'general').toLowerCase(),
      l.thickness_min ?? '',
      l.thickness_max ?? '',
      cleanText(l.thickness_unit).toLowerCase(),
      l.max_ce ?? '',
      JSON.stringify(l.applies_to_forms || []),
      JSON.stringify(l.applies_to_grades || [])
    ].join('|')
  ).map(l => ({
    ...l,
    thickness_min: normalizeNumber(l.thickness_min),
    thickness_max: normalizeNumber(l.thickness_max),
    max_ce: normalizeNumber(l.max_ce),
    row_key: makeKey(specKey, l.rule_set_key || 'general', 'ce', l.thickness_min, l.thickness_max, l.thickness_unit, (l.applies_to_grades || []).join('_'), (l.applies_to_forms || []).join('_'))
  }));

  return {
    json: {
      token: j.spec_ingest_token || '',
      spec_id: j.spec_id || (original && (original.spec_id || original.specId)) || '',
      spec_customer_key: j.spec_customer_key || '',
      spec_customer_name: j.spec_customer_name || '',
      spec_customer_confidence: j.spec_customer_confidence || 0,
      prompt_key: j.prompt_key || '',
      spec_key: specKey,
      spec_name: out.spec_name || displayName || specCode,
      spec_code: specCode,
      spec_title: specTitle,
      display_name: displayName,
      customer,
      spec_type: out.spec_type || "",
      ai_summary: out.ai_summary || "",
      branches: Array.isArray(out.branches) ? out.branches : [],
      astm_equivalent: normalizeEquivalents(out.astm_equivalent || out.astm_equivalents),
      grades: normalizeEquivalents(out.grades || out.all_grades),
      manufacturer_grades: normalizeEquivalents(out.manufacturer_grades),
      approved_substitutes: normalizeEquivalents(out.approved_substitutes),
      product_forms: productForms,
      ce_formula: out.ce_formula || '',
      chem_limits: chemLimits,
      mech_limits: mechLimits,
      impact_limits: impactLimits,
      condition_rules: conditionRules,
      ce_thresholds: ceThresholds,
      notes: out.notes || '',
      pdf_fingerprint: j.pdf_fingerprint || original.pdf_fingerprint || '',
      db_name: j.db_name || (original && (original.db_name || original.database)) || '',
      odoo_url: j.odoo_url || 'http://host.docker.internal:8069'
    }
  };
});

const promises = items.map(async (item, idx) => {
  const j = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || $items('Webhook Spec Upload')[idx]?.json || {};

  let pdf =
    j.file_content_base64 ||
    original.file_content_base64 ||
    j.file_data ||
    original.file_data ||
    '';

  if (pdf.startsWith('data:application/pdf;base64,')) {
    pdf = pdf.replace('data:application/pdf;base64,', '');
  }

  if (!pdf) {
    try {
      const buf = await this.helpers.getBinaryDataBuffer(idx, 'data0');
      pdf = buf.toString('base64');
    } catch (e) {}
  }

  if (!pdf) {
    throw new Error('Missing PDF for spec customer detection');
  }

  const prompt = `You are a strict classifier for customer steel specification PDFs.
Return ONLY valid JSON. No commentary.

Return schema:
{
  "spec_customer_key": "",
  "spec_customer_name": "",
  "confidence": 0
}

Choose spec_customer_key from this list only:
- CATERPILLAR
- HITACHI
- KOMATSU
- UNKNOWN

Rules:
- Use document header, logo, footer, title block, and specification numbering style.
- Caterpillar specs usually contain "Caterpillar", "Corporate Product & Process Specification", or spec codes like 1E0170, 1E0357, 1E0577, 1E0860.
- Hitachi specs usually contain "HITACHI Construction Truck Mfg. Ltd." or spec codes like 31121,316 or 31113,121.
- Komatsu specs usually contain "Komatsu", "Komatsu - Peoria", or spec codes like LW0090, LW0936A, LW0940, LW0968, LW1008A, LW1020A, LW5725.
- If unsure, return UNKNOWN.
- Do not extract material values here. Classification only.`;

  return {
    json: {
      ...original,
      ...j,
      file_content_base64: pdf,
      claude_spec_customer_body: {
        model: 'claude-sonnet-4-20250514',
        max_tokens: 512,
        temperature: 0,
        messages: [
          {
            role: 'user',
            content: [
              {
                type: 'document',
                source: {
                  type: 'base64',
                  media_type: 'application/pdf',
                  data: pdf
                }
              },
              {
                type: 'text',
                text: prompt
              }
            ]
          }
        ]
      }
    },
    binary: item.binary
  };
});

return Promise.all(promises);

return items.map((item, idx) => {
  const j = item.json || {};
  const original = $items('Read Binary File1')[idx]?.json || $items('Webhook Spec Upload')[idx]?.json || {};

  const text = (j.content && j.content[0] && j.content[0].text) || '';
  let obj = {};

  try {
    obj = JSON.parse(text.trim());
  } catch (e) {
    const a = text.indexOf('{');
    const b = text.lastIndexOf('}');
    if (a >= 0 && b > a) {
      try { obj = JSON.parse(text.slice(a, b + 1)); } catch (_) {}
    }
  }

  const rawKey = String(obj.spec_customer_key || obj.spec_customer_name || '').trim().toUpperCase();

  const aliases = {
    CAT: 'CATERPILLAR',
    CATERPILLAR: 'CATERPILLAR',
    'CATERPILLAR INC.': 'CATERPILLAR',
    HITACHI: 'HITACHI',
    'HITACHI CONSTRUCTION TRUCK MFG. LTD.': 'HITACHI',
    'HITACHI CONSTRUCTION TRUCK MFG LTD': 'HITACHI',
    KOMATSU: 'KOMATSU',
    'KOMATSU - PEORIA': 'KOMATSU',
    'KOMATSU PEORIA': 'KOMATSU',
    UNKNOWN: 'UNKNOWN'
  };

  const specCustomerKey = aliases[rawKey] || 'UNKNOWN';

  const names = {
    CATERPILLAR: 'Caterpillar Inc.',
    HITACHI: 'HITACHI Construction Truck Mfg. Ltd.',
    KOMATSU: 'Komatsu',
    UNKNOWN: ''
  };

  return {
    json: {
      ...original,
      ...j,
      spec_customer_key: specCustomerKey,
      spec_customer_name: names[specCustomerKey],
      spec_customer_confidence: obj.confidence || 0
    },
    binary: item.binary
  };
});
